begin;
create extension if not exists pgtap;
insert into auth.users (id, aud, role, email, encrypted_password, email_confirmed_at) values ('00000000-0000-0000-0000-000000000091', 'authenticated', 'authenticated', 'billing-owner@example.test', 'local-test-only', timezone('utc', now())) on conflict (id) do nothing;
insert into public.organizations (id, name, display_name, slug) values ('c1000000-0000-0000-0000-000000000001', 'Billing Organization', 'Billing Organization', 'billing-organization'), ('c1000000-0000-0000-0000-000000000002', 'Other Billing Organization', 'Other Billing Organization', 'other-billing-organization');
insert into public.organization_memberships (id, organization_id, profile_id, status, accepted_at) values ('c2000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000091', 'active', timezone('utc', now()));
insert into public.membership_roles (organization_id, membership_id, role_id) select 'c1000000-0000-0000-0000-000000000001', 'c2000000-0000-0000-0000-000000000001', id from public.roles where key = 'organization.owner';
select plan(15);
set local role anon;
select throws_ok($$select public.create_invoice('c1000000-0000-0000-0000-000000000001', gen_random_uuid(), null, null, 'CAD', null, 0, null, '[{"description":"Denied","quantity":1,"unitPrice":10}]'::jsonb)$$, 'P0001', 'Permission denied', 'anonymous invoice creation is denied');
set local role authenticated;
select set_config('request.jwt.claim.sub', '00000000-0000-0000-0000-000000000091', true);
create temp table billing_patient on commit drop as select * from public.create_patient('c1000000-0000-0000-0000-000000000001', 'BL-001', 'Billing', null, 'Patient', null, null, '1980-01-01', 'undisclosed', null, null, 'undisclosed', null, 'en', false, null, null, null, 'active', null, null);
select throws_ok($$insert into public.invoices(organization_id, patient_id, invoice_number) values ('c1000000-0000-0000-0000-000000000001', (select patient_id from billing_patient), 'DENIED')$$, '42501', null, 'direct invoice writes are denied');
create temp table created_invoice on commit drop as select public.create_invoice('c1000000-0000-0000-0000-000000000001', (select patient_id from billing_patient), null, null, 'CAD', '2026-09-01', 5, 'Test invoice', '[{"description":"Consultation","quantity":1,"unitPrice":100,"taxRate":5}]'::jsonb) as invoice_id;
select is((select status from public.invoices limit 1), 'draft', 'invoice starts as draft');
select is((select total from public.invoices limit 1), 100::numeric, 'invoice total includes bounded discount and tax');
select lives_ok($$select public.issue_invoice((select invoice_id from created_invoice))$$, 'invoice can be issued');
select is((select status from public.invoices limit 1), 'issued', 'invoice is issued');
create temp table created_payment on commit drop as select public.record_payment('c1000000-0000-0000-0000-000000000001', (select patient_id from billing_patient), 'cash', 50, 'CAD', 'CASH-001') as payment_id;
select lives_ok($$select public.allocate_payment((select payment_id from created_payment), (select invoice_id from created_invoice), 50)$$, 'payment can be allocated');
select is((select balance from public.invoices limit 1), 50::numeric, 'allocation reduces invoice balance');
select is((select status from public.invoices limit 1), 'partially_paid', 'partial allocation updates invoice state');
select lives_ok($$select public.generate_receipt((select payment_id from created_payment))$$, 'receipt can be generated once');
select is((select count(*)::integer from public.receipts), 1, 'receipt record is created');
select lives_ok($$select public.create_credit_note((select invoice_id from created_invoice), 50, 'full', 'Service adjustment')$$, 'credit note adjusts remaining balance');
select is((select balance from public.invoices limit 1), 0::numeric, 'credit note clears remaining balance');
set local role postgres;
select is((select count(*)::integer from public.billing_events where organization_id = 'c1000000-0000-0000-0000-000000000001'), 6, 'billing mutations create events');
select ok((select count(*) from public.audit_events where organization_id = 'c1000000-0000-0000-0000-000000000001' and action like 'billing.%') >= 6, 'billing mutations create audit events');
select * from finish();
rollback;
